export function getMadinahHotelByCode(code: number) {
  return madinahHotels.find(h => h.code === code);
}

export function getGoogleMapsSearchLink(hotelName: string) {
  const q = encodeURIComponent(`${hotelName} Madinah Saudi Arabia`);
  return `https://www.google.com/maps/search/?api=1&query=${q}`;
}
